package be.schaubroeck.lpb.rkm.rekenmotor.bruto;

import be.schaubroeck.lpb.rkm.rekenmotor.LoonElement;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.SleutelGegevens;
import be.schaubroeck.lpb.tools.AardKodeExtensie;
import be.schaubroeck.lpb.tools.Money;
import be.schaubroeck.lpb.tools.enumtypes.Konstanten;
import be.schaubroeck.lpb.tools.enumtypes.Regulkode;
import org.joda.time.LocalDate;

import java.math.BigDecimal;
import java.util.Set;

public class LoonCodeCalculatorOnregelmatigWerkgeverUurloon extends AbstractLoonCodeCalculator {

    public LoonCodeCalculatorOnregelmatigWerkgeverUurloon(
            SleutelGegevens gegevens, AardKodeExtensie aardKodeExtensie, RekenTijd rekenTijd,
            Set<LoonElement> supplementenFase1, BigDecimal index, LoonCodeCalculatorFactory factory) {
        super(gegevens, aardKodeExtensie, rekenTijd, factory, supplementenFase1, index);
    }

    @Override
    public Money berekenBedrag100Percent(Money ongebruikt) {
        LocalDate constanteDatum = rekenTijd.beginDatum;
        Money returnValue;
        Money constanteBedrag = Money.ZERO;
        if (aardKodeExtensie.getConst1nr() != 0) {
            constanteBedrag = constantManager.getByCodeDatum(aardKodeExtensie.getConst1nr(), constanteDatum).getMoney();
        }

        if (aardKodeExtensie.getConst2nr() == 0 || aardKodeExtensie.getConst4nr().equals(Konstanten.CST_BAREMA_KORPORAAL.getCode())) {
            returnValue = constanteBedrag;
        } else {
            BigDecimal constanteFactor = constantManager.getByCodeDatum(aardKodeExtensie.getConst2nr(), constanteDatum).getProcentFactor();
            if (zonderToeslag) {
                constanteFactor = (constanteFactor.compareTo(BigDecimal.ONE) >= 0) ? BigDecimal.ONE : BigDecimal.ZERO;
            }
            BigDecimal uurnoemer;

            if (aardKodeExtensie.getConst3nr() != 0) {
                uurnoemer = BigDecimal.valueOf(constantManager.getByCodeDatum(aardKodeExtensie.getConst3nr(), constanteDatum).getInteger());
            } else {
                uurnoemer = BigDecimal.valueOf(gegevens.getUurNoemer());
            }

            if (uurnoemer.signum() == 0) {
                regulManager.doRegulException(gegevens.getOpdracht(), Regulkode.UURNOEMER_NUL);
                uurnoemer = BigDecimal.valueOf(1976);
            }
            returnValue = constanteBedrag.add(basisBedrag().multiply(constanteFactor).divide(uurnoemer));
        }

        if (aardKodeExtensie.getConst4nr() != 0) {
            BigDecimal constanteFactor2 = constantManager.getByCodeDatum(aardKodeExtensie.getConst4nr(), constanteDatum).getProcentFactor();
            returnValue = returnValue.multiply(constanteFactor2);
        }

        return returnValue;
    }
}
